+};
+
+function current(world: World): DeferredBuffer {
+    const buffers = world[$internal].deferredBuffers;
+    if (!buffers.length) buffers.push({ commands: [], spawned: new Set() });
+    return buffers[buffers.length - 1];
+}
+
+export function pushDeferredScope(world: World) {
+    world[$internal].deferredBuffers.push({ commands: [], spawned: new Set() });
+}
+
+export function popDeferredScope(world: World) {
+    const buffer = world[$internal].deferredBuffers.pop();
+    if (buffer) flushBuffer(world, buffer);
+}
+
+export function createDeferredCommands(world: World): DeferredCommands {
+    return {
+        spawn(...traits) {
+            // Reserve an entity id now so it can be used by later deferred commands.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            const buffer = current(world);
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            current(world).commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            current(world).commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            current(world).commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            if (!isRelationPair(pair)) throw new Error('Koota: addExclusive requires a relation pair.');
+            current(world).commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            const buffer = current(world);
+            flushBuffer(world, buffer);
+            buffer.commands.length = 0;
+            buffer.spawned.clear();
+        },
+    };
+}
+
+/** Flush every active scope that contains commands for an immediate entity mutation. */
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    const buffers = world[$internal].deferredBuffers;
+    if (!buffers.some((buffer) => buffer.commands.some((command) => command.entity === entity))) return;
+    for (const buffer of buffers) {
+        flushBuffer(world, buffer);
+        buffer.commands.length = 0;
+        buffer.spawned.clear();
+    }
+}
+
+function initializeSpawn(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    const ctx = world[$internal];
+    // A reservation can have been nullified by a destroy command.
+    if (!world.has(entity) || ctx.entityTraits.has(entity)) return;
+    for (const query of ctx.notQueries) {
+        if (query.check(world, entity)) query.add(entity);
+        query.resetTrackingBitmasks(getEntityId(entity));
+    }
+    ctx.entityTraits.set(entity, new Set());
+    addTrait(world, entity, ...traits);
+}
+
+function flushBuffer(world: World, buffer: DeferredBuffer) {
+    // Spawn followed by destroy has no externally observable state, including subscriptions.
+    const nullified = new Set<Entity>();
+    for (const command of buffer.commands) {
+        if (command.type === 'destroy' && buffer.spawned.has(command.entity)) nullified.add(command.entity);
+    }
+
+    for (const command of buffer.commands) {
+        if (nullified.has(command.entity)) continue;
+        if (command.type === 'spawn') {
+            initializeSpawn(world, command.entity, command.traits);
+            continue;
+        }
+        if (command.type === 'destroy') {
+            if (command.entity === world[$internal].worldEntity) {
+                throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+            }
+            if (world.has(command.entity)) destroyEntity(world, command.entity);
+            continue;
+        }
+        // Commands targeting entities destroyed earlier in this flush are intentionally no-ops.
+        if (!world.has(command.entity) || !world[$internal].entityTraits.has(command.entity)) continue;
+        if (command.type === 'add') addTrait(world, command.entity, ...command.traits);
+        else if (command.type === 'remove') removeTrait(world, command.entity, ...command.traits);
+        else {
+            const pairCtx = command.pair[$internal];
+            const relation = pairCtx.relation;
+            // The wildcard form is a convenient "clear this relation" operation.
+            removeTrait(world, command.entity, relation('*'));
+            if (pairCtx.target !== '*') addTrait(world, command.entity, command.pair);
+        }
