+/** The deferred view used by Entity#has. */
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean {
+    let alive = world.has(entity) && world[$internal].entityTraits.has(entity);
+    let value = isRelationPair(trait)
+        ? hasRelationPair(world, entity, trait)
+        : hasTrait(world, entity, trait);
+    const relationPair = isRelationPair(trait) ? trait : undefined;
+    for (const buffer of world[$internal].deferredBuffers) for (const command of buffer.commands) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'spawn') { alive = true; continue; }
+        if (command.type === 'destroy') { alive = false; value = false; continue; }
+        if (!alive) continue;
+        const matches = (item: Trait | RelationPair) => {
+            if (relationPair) {
+                if (!isRelationPair(item)) return false;
+                const a = item[$internal], b = relationPair[$internal];
+                return a.relation === b.relation && (b.target === '*' || a.target === b.target);
+            }
+            return !isRelationPair(item) && item === trait;
+        };
+        if (command.type === 'add' && command.traits.some(matches)) value = true;
+        if (command.type === 'remove' && command.traits.some(matches)) value = false;
+        if (command.type === 'exclusive' && relationPair && command.pair[$internal].relation === relationPair[$internal].relation) {
+            value = command.pair[$internal].target !== '*' && command.pair[$internal].target === relationPair[$internal].target;
+        }
+    }
+    return alive && value;
+}
